// src/components/UI/ModelLoadingIndicator.jsx
import React, { useEffect, useState } from 'react';

function ModelLoadingIndicator() {
  const [isLoading, setIsLoading] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);
  const [currentModel, setCurrentModel] = useState('');
  const [errorMessage, setErrorMessage] = useState('');
  
  useEffect(() => {
    // Event handler for progress updates
    const handleProgress = (event) => {
      const { modelType, progress } = event.detail;
      setIsLoading(true);
      setLoadingProgress(progress);
      setCurrentModel(modelType);
      
      // Clear loading state when complete
      if (progress === 100) {
        setTimeout(() => {
          setIsLoading(false);
        }, 500); // Short delay to show 100% before hiding
      }
    };
    
    // Event handler for loading complete
    const handleComplete = (event) => {
      const { modelType } = event.detail;
      setLoadingProgress(100);
      setCurrentModel(modelType);
      
      // Clear loading state after a short delay
      setTimeout(() => {
        setIsLoading(false);
      }, 500);
    };
    
    // Event handler for errors
    const handleError = (event) => {
      const { modelType, error } = event.detail;
      setErrorMessage(`Failed to load ${modelType}: ${error.message}`);
      setIsLoading(false);
      
      // Clear error after 5 seconds
      setTimeout(() => {
        setErrorMessage('');
      }, 5000);
    };
    
    // Event handler for placeholder creation
    const handlePlaceholder = (event) => {
      const { modelType } = event.detail;
      console.log(`Using placeholder for ${modelType}`);
    };
    
    // Add event listeners
    window.addEventListener('model-load-progress', handleProgress);
    window.addEventListener('model-load-complete', handleComplete);
    window.addEventListener('model-load-error', handleError);
    window.addEventListener('model-placeholder-created', handlePlaceholder);
    
    // Remove event listeners on cleanup
    return () => {
      window.removeEventListener('model-load-progress', handleProgress);
      window.removeEventListener('model-load-complete', handleComplete);
      window.removeEventListener('model-load-error', handleError);
      window.removeEventListener('model-placeholder-created', handlePlaceholder);
    };
  }, []);
  
  // Don't render anything if not loading and no error
  if (!isLoading && !errorMessage) {
    return null;
  }
  
  return (
    <>
      {/* Loading indicator */}
      {isLoading && (
        <div className="loading-overlay">
          <div className="spinner"></div>
          <div className="progress-bar">
            <div 
              className="progress-fill" 
              style={{ width: `${loadingProgress}%` }}
            ></div>
          </div>
          <p>Loading {currentModel}... {loadingProgress}%</p>
        </div>
      )}
      
      {/* Error message */}
      {errorMessage && (
        <div className="error-message">
          <p>{errorMessage}</p>
          <button onClick={() => setErrorMessage('')}>Dismiss</button>
        </div>
      )}
    </>
  );
}

export default ModelLoadingIndicator;
